-- Modify "purchase_receipt_items" table
ALTER TABLE "purchase_receipt_items" ADD CONSTRAINT "purchase_receipt_items_idempotency_bundle_complete" CHECK (((idempotency_key IS NULL) AND (idempotency_payload_hash IS NULL)) OR ((idempotency_key IS NOT NULL) AND ((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)) AND (idempotency_payload_hash IS NOT NULL) AND (length((idempotency_payload_hash)::text) = 64))), ADD COLUMN "idempotency_key" character varying NULL, ADD COLUMN "idempotency_payload_hash" character varying NULL;
-- Create index "purchasereceiptitem_receipt_id_idempotency_key" to table: "purchase_receipt_items"
CREATE UNIQUE INDEX "purchasereceiptitem_receipt_id_idempotency_key" ON "purchase_receipt_items" ("receipt_id", "idempotency_key") WHERE ((idempotency_key IS NOT NULL) AND ((idempotency_key)::text <> ''::text));
-- Modify "purchase_receipts" table
ALTER TABLE "purchase_receipts" ADD CONSTRAINT "purchase_receipts_idempotency_bundle_complete" CHECK (((idempotency_key IS NULL) AND (idempotency_payload_hash IS NULL) AND (idempotency_item_count IS NULL)) OR ((idempotency_key IS NOT NULL) AND ((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)) AND (idempotency_payload_hash IS NOT NULL) AND (length((idempotency_payload_hash)::text) = 64) AND (idempotency_item_count IS NOT NULL) AND (idempotency_item_count > 0)));
